mapper.select:
SELECT c.content_id AS content_id, c.title AS title, c.main_image_path AS main_image_path, c.location AS location, c.start_at AS start_at, c.end_at AS end_at FROM content c WHERE c.is_active = true AND c.is_delete = false AND c.content_status IN ('STATUS_OPEN', 'STATUS_SCHEDULED')
AND c.content_kind=#{content_kind}
ORDER BY RAND() LIMIT #{limit}

SELECT c. content_id AS content_id, c. title AS title, c. main_image_path AS main_image_path, c. location AS location, c.start_at AS start_at, c.end_at AS end_at FROM content c WHERE c.is_active=true AND c.is_delete=false AND c.content_status = 'STATUS_OPEN'
AND c.content_id IN ( SELECT DISTINCT ct.content_id FROM content_tag ct WHERE ct.tag_id IN
#{ut.tag_id}
)
LIMIT #{limit}

SELECT c.content_id AS contentId, c.title AS title, c.main_image_path AS main_image_path, c.category AS category, c.location AS location, c.start_at AS start_at, c.end_at AS end_at FROM content c LEFT JOIN ( SELECT content_id, COUNT(*) AS res_cnt FROM reservation WHERE created_at >= DATE_SUB(NOW(), INTERVAL 30 DAY) AND reservation_status IN ('PAID','CONFIRMED') GROUP BY content_id ) r ON r.content_id = c.content_id LEFT JOIN ( SELECT content_id, COUNT(*) AS like_cnt FROM content_like GROUP BY content_id ) l ON l.content_id = c.content_id WHERE
AND c.content_status IN ('STATUS_SCHEDULED','STATUS_OPEN')
AND c.content_kind = #{kind}
ORDER BY (COALESCE(r.res_cnt,0)*3 + COALESCE(l.like_cnt,0)) DESC, c.start_at ASC LIMIT #{limit}

SELECT c.content_id AS contentId, c.title AS title, c.main_image_path AS main_image_path, c.category AS category, c.content_kind AS content_kind, c.location AS location, c.start_at AS start_at, c.end_at AS end_at FROM content c WHERE
AND c.content_status = 'STATUS_SCHEDULED'
AND c.content_kind = #{kind}
ORDER BY c.start_at ASC LIMIT #{limit}

SELECT COUNT(*) FROM content c
AND c.content_status != 'STATUS_CLOSED'
AND ( c.title LIKE CONCAT('%', #{dto.q}, '%') OR c.description LIKE CONCAT('%', #{dto.q}, '%') OR c.location LIKE CONCAT('%', #{dto.q}, '%') )
AND c.content_kind = #{dto.content_kind}
AND c.category IN
#{cat}
AND c.place_tag IN
#{pt}
AND c.reservation_type = #{dto.reservation_type}
AND c.adult_price = 0
AND c.start_at >= STR_TO_DATE(CONCAT(#{dto.start_at}, ' 00:00:00'), '%Y-%m-%d %H:%i:%s')
AND c.end_at <= STR_TO_DATE(CONCAT(#{dto.end_at}, ' 23:59:59'), '%Y-%m-%d %H:%i:%s')

SELECT time_zone, current_ticket, schedule_id
FROM content_schedule
WHERE content_id=#{content_id}
AND scheduled_at= #{scheduled_at}
ORDER BY time_zone
